+/** Run Tasks serially, stopping before invoking the mapper after a rejection. */
+export function traverseSerial<T, U, E>(items: Iterable<T>, fn: (item: T) => Task<U, E>): Task<U[], E>;
+export function traverseSerial<T, U, E>(fn: (item: T) => Task<U, E>): (items: Iterable<T>) => Task<U[], E>;
+export function traverseSerial<T, U, E>(
+  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
+  taskFn?: (item: T) => Task<U, E>
+): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
+  if (taskFn === undefined) return (items) => traverseSerial(items, itemsOrFn as (item: T) => Task<U, E>);
+  const iterator = (itemsOrFn as Iterable<T>)[Symbol.iterator]();
+  const values: U[] = [];
+  const next = (): Task<U[], E> => {
+    const item = iterator.next();
+    if (item.done) return Task.resolve(values);
+    return taskFn(item.value).andThen((value) => {
